<template>


	<view class="wrap">

		<u-navbar :custom-back="backpage">



			<!-- 如果使用u-search组件，必须要给v-model绑定一个变量 -->
			<u-search disabled v-model="keyword" placeholder="请选择变动类型" @click="show =true" :show-action="false"
				height="56" @search="search" @custom="search" bg-color="#f5f7fa">
			</u-search>


			<view slot="right" style="width: 90rpx;display: flex;
    justify-content: center;" @click="show = true">
				<u-icon name="more-dot-fill" size="38"></u-icon>

				<u-select v-model="show" :list="typeList" @confirm="confirm"></u-select>
			</view>

		</u-navbar>



		<scroll-view scroll-y style="height: 100%;width: 100%;background-color: #f5f7fa;" @scrolltolower="reachBottom">
			<view class="page-box">
				<view class="order" v-for="(order, orderindex) in list" :key="order.id">
					<!-- <view class="top">
						<view class="left" >

							<view class="store"  style="font-size: 32rpx;">{{ order._trade_type_text }}</view>
				
						</view>
					
					</view> -->
					<view class="item" @click="topage(order)">

						<view class="content">
							<view class="content-box">
								<view class="store" style="font-size: 32rpx;font-weight: bold;">
									{{ order.trade_type_text }}
								</view>
							</view>
							<view class="content-box">
								<view class="label">
									之前金额 {{order.before}}
								</view>
								<view class="label">
									之后金额 {{order.after}}
								</view>

							</view>
							<view class="content-box" style="color:#ccc;">
								{{ $util.timeFormat(order.create_time,'yyyy年mm月dd日 hh:MM:ss') }}
							</view>

						</view>
						<view class="money-box" :style="order.change_type == 1 ?'color:red;':'color:green;'">
							{{order.change_type == 1 ?'+':'-'}}{{order.money}}
						</view>
					</view>

					<!-- <view class="bottom"> -->
					<!-- <view class="more">
										<u-icon name="more-dot-fill" color="rgb(203,203,203)"></u-icon>
									</view> -->
					<!-- <view class="logistics btn">详情</view> -->

					<!-- <view class="evaluate btn" v-if="order.status == 0">立即支付</view> -->
					<!-- 	<view class="exchange btn" @click="$util.on('/pages/buyer/addcomplain?ordersn='+order.ordersn)">查看详情
						</view> -->

					<!-- </view> -->
				</view>


				<u-loadmore :status="loadStatus" icon-type="circle" v-if="list.length >0 && loaded" />
			</view>
			<u-empty v-if="loaded &&  list.length == 0"></u-empty>


		</scroll-view>


	</view>



</template>

<script>
	export default {
		data() {
			return {

				keyword: '',
				sys: this.$util.sys(),
				limit: 10,


				loadStatus: 'loadmore',
				page: 1,

				count: 0,
				list: [],
				loaded: false,
				statusColor: [{
						color: '#999'
					},


					{
						color: '#90dd90'
					},

					{
						color: '#f00'
					}
				],

				current: 0,
				swiperCurrent: 0,

				typeList: [], //资金明细类型
				type: 0,
				show: false,
				dx: 0,
			};
		},
		onLoad(e) {


			if (e.status) {
				this.swiperCurrent = e.status
				this.current = e.status

			}

			this.getConfig();
			this.loadData(this.swiperCurrent);
		},
		methods: {
			backpage() {
				this.$util.back()
			},
			getConfig() {
				this.$u.api.moneydetailConfig({})
					.then(res => {
						this.typeList = res.typeList
					}).catch(res => {})

			},
			topage(item) {

				switch (item.trade_type) {
					case '1':
					case '2':
						this.$util.on('/pages/order/info?id=' + item.extend_id)
						break;
					case '17':
					case '18':
						this.$util.on('/pages/ucenter_sub/drawlog')
						break;

				}

			},
			confirm(e) {
				if (e[0].value == 0) {
					this.type = e[0].value
					this.keyword = ''
				} else {
					this.type = e[0].value
					this.keyword = e[0].label
				}
				this.search()

			},
			paste(val) {

				uni.setClipboardData({
					data: val,
					success: function() {
						uni.showToast({
							title: '复制成功',
							mask: false,
							duration: 1500,
							icon: 'none'
						});
					}
				})
			},
			reachBottom() {


				setTimeout(() => {
					this.loadData(this.current);
				}, 200);

			},
			search() {
				this.list = []
				this.page = 1
				this.loaded = false
				this.current = 0
				this.swiperCurrent = 0
				this.loadData(0);

			},
			// 页面数据
			async loadData(idx) {
				uni.showLoading({
					mask: true,
					title: '加载中...',

				})

				let trade_type = this.type || '';

				await this.$u.api.moneydetail({

						keyword: this.keyword,
						type: trade_type,
						page: this.page,
						limit: this.limit,
					})
					.then(res => {
						if (res.list.length == 0) {
							this.loadStatus = 'nomore'
						} else {
							if (this.list.length > 0) {
								this.list = this.list.concat(res.list)

							} else {
								this.list = res.list

							}

							if (res.list.length < this.limit) {
								this.loadStatus = 'nomore'
							} else {
								this.loadStatus = 'loadmore'
							}


							this.page++
						}
					}).catch(res => {})

				this.loaded = true;
				//loaded新字段用于表示数据加载完毕，如果为空可以显示空白页
				uni.hideLoading()
				// console.log(item	);
			},
			// 总价
			totalPrice(item) {
				let price = 0;
				item.map(val => {
					price += parseFloat(val.price);
				});
				return price.toFixed(4);
			},
			// 总件数
			totalNum(item) {
				let num = 0;
				item.map(val => {
					num += val.number;
				});
				return num;
			},
			// tab栏切换
			change(index) {
				this.swiperCurrent = index;
				this.loadData(index);
			},
			transition({
				detail: {
					dx
				}
			}) {

				this.$refs.tabs.setDx(dx);
			},
			animationfinish({
				detail: {
					current
				}
			}) {

				this.$refs.tabs.setFinishCurrent(current);
				this.swiperCurrent = current;
				this.current = current;
				if (!this.orderList[current].loaded) {
					this.loadData(current)
				}
			}
		}
	};
</script>

<style scoped>

</style>

<style lang="scss" scoped scoped>
