			align-items: center;

			.left {
				margin-right: 20rpx;

				image {
					width: 160rpx;
					height: 160rpx;
					border-radius: 10rpx;
				}
			}

			.content {

				display: flex;
				gap: 4rpx;
				flex-direction: column;

				.title {
					font-size: 28rpx;
					line-height: 50rpx;
				}

				.type {
					margin: 10rpx 0;
					font-size: 24rpx;
					color: $u-tips-color;
				}

				.delivery-time {
					// color: #e5d001;
					font-size: 24rpx;
				}

				.content-box {
					display: flex;
					gap: 20rpx;


				}
			}

			.money-box {
				font-size: 40rpx;
				font-weight: 500;
			}

			.right {
				margin-left: 10rpx;
				padding-top: 8rpx;
